using Ledgerly.Domain.Common; using Ledgerly.Domain.Exceptions; using Ledgerly.Domain.ValueObjects; namespace Ledgerly.Domain.Entities; public sealed class InvoiceLine:Entity{ public Guid InvoiceId{get;private set;} public string Description{get;private set;}=string.Empty; public decimal Quantity{get;private set;} public Money UnitPrice{get;private set;} public Guid? TaxCodeId{get;private set;} public Money Discount{get;private set;} private InvoiceLine(){UnitPrice=new Money(0m,new CurrencyCode("USD"));Discount=new Money(0m,new CurrencyCode("USD"));} internal InvoiceLine(Guid invoiceId,string description,decimal quantity,Money unitPrice,Guid? taxCodeId,Money discount){InvoiceId=invoiceId; if(string.IsNullOrWhiteSpace(description))throw new DomainException("Line description is required."); if(quantity<=0m)throw new DomainException("Quantity must be greater than zero."); Description=description.Trim(); Quantity=quantity; UnitPrice=unitPrice; TaxCodeId=taxCodeId; Discount=discount;} public Money GetNetAmount()=>new Money(Math.Round(Quantity*UnitPrice.Amount,2,MidpointRounding.AwayFromZero),UnitPrice.Currency)-Discount; public Money GetTaxAmount(decimal taxRate)=>taxRate<=0m||!TaxCodeId.HasValue?new Money(0m,UnitPrice.Currency):new Money(Math.Round(GetNetAmount().Amount*taxRate,2,MidpointRounding.AwayFromZero),UnitPrice.Currency);
public Money GetTaxAmount(TaxCode? taxCode)=>taxCode is null||!TaxCodeId.HasValue?new Money(0m,UnitPrice.Currency):new Money(taxCode.CalculateTaxAmount(GetNetAmount().Amount),UnitPrice.Currency); }
